import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { forkJoin } from 'rxjs';
import { Category, PublicProduct } from '../models';
import { StoreApiService } from '../services/store-api.service';
import { ProductCardComponent } from '../components/product-card.component';
import { PaginationComponent } from '../components/pagination.component';

@Component({
  selector: 'app-catalog-page',
  standalone: true,
  imports: [CommonModule, FormsModule, ProductCardComponent, PaginationComponent],
  template: `
    <section class="hero">
      <h1>Tienda pública de productos</h1>
      <p>Explora el catálogo y entra al producto para ver la compra.</p>
    </section>

    <section class="filters">
      <input
        type="search"
        [(ngModel)]="search"
        name="search"
        placeholder="Buscar por nombre, SKU o descripción"
        (keyup.enter)="applyFilters()"
      />

      <select [(ngModel)]="categoria" name="categoria">
        <option value="">Todas las categorías</option>
        <option *ngFor="let item of categories" [value]="item.id">{{ item.nombre }}</option>
      </select>

      <button type="button" (click)="applyFilters()">Buscar</button>
    </section>

    <div *ngIf="loading" class="empty">Cargando catálogo...</div>
    <div *ngIf="error" class="error">{{ error }}</div>

    <ng-container *ngIf="!loading && !error">
      <div *ngIf="products.length === 0" class="empty">No se encontraron productos.</div>

      <section class="grid" *ngIf="products.length > 0">
        <app-product-card *ngFor="let product of products" [product]="product"></app-product-card>
      </section>

      <app-pagination
        [page]="page"
        [totalPages]="totalPages"
        (pageChange)="goToPage($event)"
      />
    </ng-container>
  `,
})
export class CatalogPageComponent implements OnInit {
  products: PublicProduct[] = [];
  categories: Category[] = [];
  loading = true;
  error = '';
  search = '';
  categoria = '';
  page = 1;
  totalPages = 1;

  constructor(private readonly storeApi: StoreApiService) {}

  ngOnInit(): void {
    this.loadData();
  }

  applyFilters(): void {
    this.page = 1;
    this.loadData();
  }

  goToPage(nextPage: number): void {
    this.page = nextPage;
    this.loadData();
  }

  private loadData(): void {
    this.loading = true;
    this.error = '';

    forkJoin({
      catalog: this.storeApi.getCatalog({
        page: this.page,
        limit: 12,
        search: this.search.trim() || undefined,
        categoria: this.categoria || undefined,
      }),
      categories: this.storeApi.getCategories(),
    }).subscribe({
      next: ({ catalog, categories }) => {
        this.products = catalog.data;
        this.categories = categories;
        this.page = catalog.page;
        this.totalPages = catalog.totalPages || 1;
        this.loading = false;
      },
      error: () => {
        this.error = 'No se pudo cargar la tienda pública.';
        this.loading = false;
      },
    });
  }
}
